MAX_QUERY_LENGTH = 10000
MAX_RESULTS = 1000
QUERY_TIMEOUT = 5000

ALLOWED_STATEMENTS = ['SELECT']
FORBIDDEN_PATTERNS = [
    r';\s*DROP',
    r';\s*DELETE',
    r';\s*UPDATE',
    r';\s*INSERT',
    r';\s*CREATE',
    r';\s*ALTER',
    r';\s*TRUNCATE',
    r'--',
    r'/\*',
    r'xp_',
    r'sp_',
    r'EXEC\s',
    r'EXECUTE\s',
]

def validate_query(query: str) -> bool:
    if not query or len(query) > MAX_QUERY_LENGTH:
        return False
    
    query_upper = query.upper().strip()
    
    if not any(query_upper.startswith(stmt) for stmt in ALLOWED_STATEMENTS):
        return False
    
    for pattern in FORBIDDEN_PATTERNS:
        if re.search(pattern, query, re.IGNORECASE):
            return False
    
    semicolon_count = query.count(';')
    if semicolon_count > 1 or (semicolon_count == 1 and not query.strip().endswith(';')):
        return False
    
    return True

def sanitize_table_name(table_name: str) -> str:
    if not re.match(r'^[a-zA-Z0-9_]+$', table_name):
        raise ValueError("Invalid table name")
    return table_name

def get_db_connection():
    conn = psycopg2.connect(
        host=DB_HOST,
        port=DB_PORT,
        database=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
        connect_timeout=5,
        options=f'-c statement_timeout={QUERY_TIMEOUT}'
    )
    conn.set_session(readonly=True, autocommit=True)
    return conn

def execute_query(query: str, params: tuple = None) -> List[Dict[str, Any]]:
    conn = None
    cursor = None
    try:
        conn = get_db_connection()
        cursor = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        
        if params:
            cursor.execute(query, params)
        else:
            cursor.execute(query)
        
        results = cursor.fetchmany(MAX_RESULTS)
        
        return [dict(row) for row in results]
    
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()

